-- 1. הקמת התשתית (Schema)
CREATE TABLE IF NOT EXISTS concepts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    unit_id INTEGER,
    term TEXT NOT NULL,
    definition_official TEXT,
    memory_concrete_asd TEXT
);

CREATE TABLE IF NOT EXISTS reports (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    student_id TEXT,
    content TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 2. ניקוי נתונים ישנים
DELETE FROM concepts;

-- 3. הזרקת הנתונים (כל 112 המושגים)
INSERT INTO concepts (unit_id, term, definition_official, memory_concrete_asd) VALUES 
-- יחידה 1: הרקע ההיסטורי והחלטה 181
(1, 'הקונגרס הציוני הראשון (1897)', 'התכנסות בבאזל ביוזמת הרצל להקמת בית לאומי לעם היהודי בארץ ישראל.', '1897: הרצל חזה בבאזל הקמת בית לאומי ליהודים בארץ ישראל!'),
(1, 'הצהרת בלפור (1917)', 'מסמך תמיכה בריטי המכיר בזכות העם היהודי לבית לאומי בארץ ישראל.', '1917: בריטניה תמכה בבית לאומי ליהודים בארץ ישראל!'),
(1, 'כתב המנדט (1922)', 'הסמכה של חבר הלאומים לבריטניה לשלוט בארץ ולקדם את הקמת הבית הלאומי.', '1922: חבר הלאומים נתן לבריטניה מנדט להקים בית לאומי!'),
(1, 'הרקע להחלטה', 'סכסוך היסטורי בין התנועה הלאומית היהודית והערבית על השליטה בארץ ישראל.', 'סכסוך בין יהודים וערבים על אותו שטח - שני עמים, ארץ אחת!'),
(1, 'החלטה 181 (1947)', 'החלטת עצרת האו"ם על חלוקת ארץ ישראל למדינה יהודית ולמדינה ערבית.', '1947: האו"ם החליט לחלק את הארץ לשתי מדינות - יהודית וערבית!'),
(1, '4 החלטות שנקבעו ב-181', 'סיום המנדט, הקמת שתי מדינות, משטר דמוקרטי, ובינאום ירושלים.', 'דמוקרטיה, אסיפה מכוננת, עזיבת בריטניה, מועצה כלכלית משותפת!'),
(1, 'הקו הירוק (1949)', 'קווי שביתת הנשק שנקבעו בין ישראל למדינות ערב לאחר מלחמת העצמאות.', '1949: קו שביתת הנשק בין ישראל לשכנות - צבוע בירוק על המפה!'),

-- יחידה 2: המגילה ומלחמת העצמאות
(2, 'מגילת העצמאות (1948)', 'מסמך ההכרזה על הקמת מדינת ישראל המפרט את אופייה וערכיה.', '14.5.1948: בן-גוריון הכריז על הקמת מדינת ישראל!'),
(2, 'עקרונות המגילה', 'הבטחת אופייה של ישראל כמדינה יהודית ודמוקרטית המחויבת לשוויון זכויות.', 'מדינה יהודית ודמוקרטית - זכויות שוות לכל אזרח!'),
(2, 'מלחמת העצמאות (1948-1949)', 'המלחמה שפרצה בעקבות החלטת החלוקה והכרזת המדינה.', '1948-1949: מלחמה על קיום המדינה מול צבאות ערב!'),
(2, 'תוצאות המלחמה', 'הקמת המדינה בפועל, הרחבת גבולותיה והיווצרות בעיית הפליטים.', 'ניצחון! שטח גדול יותר, 700 אלף פליטים, הקו הירוק!'),
(2, 'הסכמי שביתת הנשק (1949)', 'הסכמים שסיימו את מלחמת העצמאות וקבעו את גבולות הקו הירוק.', '1949: הסכמי רודוס - שביתת נשק עם מצרים, ירדן, סוריה, לבנון!'),
(2, 'עלייה גדולה (1948-1951)', 'גלי עלייה המוניים בשנים הראשונות להקמת המדינה, רובם מארצות אסיה ואפריקה.', '1948-1951: 700 אלף עולים הגיעו - רובם מארצות ערב!'),
(2, 'חוק השבות (1950)', 'חוק המעניק זכות לכל יהודי לעלות לישראל ולהפוך לאזרח המדינה.', '1950: כל יהודי בעולם זכאי לעלות לארץ ישראל!'),

-- יחידה 3: משטר הדמוקרטיה בישראל
(3, 'דמוקרטיה', 'שיטת ממשל שבה הריבונות שייכת לאזרחים המשתתפים בקבלת ההחלטות.', 'העם בוחר מי ינהל - לא מלך או דיקטטור!'),
(3, 'הפרדת רשויות', 'פיצול כוח השלטון לרשות מחוקקת, מבצעת ושופטת כדי למנוע עריצות.', 'שלושה כוחות - כנסת מחוקקת, ממשלה מבצעת, בג"ץ שופט!'),
(3, 'חוקי יסוד', 'פרקי החוקה העתידית של מדינת ישראל, בעלי מעמד משפטי עליון מתוקף פסיקת בית המשפט.', 'חוקים חזקים שקשה לשנות - כמו חוקה למדינה!'),
(3, 'הכנסת', 'הרשות המחוקקת של מדינת ישראל המונה 120 נציגים נבחרים.', '120 חברי כנסת בירושלים מחליטים על חוקי ישראל!'),
(3, 'הממשלה', 'הרשות המבצעת בישראל, האחראית על ניהול ענייני המדינה הפנים והחוץ.', 'ראש הממשלה ושריו מנהלים את המדינה מדי יום!'),
(3, 'בג"ץ', 'בית המשפט העליון בשבתו כבית משפט גבוה לצדק, שתפקידו להגן על זכויות אדם מפני רשויות השלטון.', 'בית המשפט הגבוה לצדק בודק את הממשלה והכנסת!'),

-- יחידה 4: זכויות האזרח והקבוצות בישראל
(4, 'זכויות אדם', 'זכויות טבעיות המוקנות לכל אדם באשר הוא אדם (חיים, חירות, קניין).', 'כל אדם בישראל זכאי לחיים בכבוד, בריאות וחינוך - זה חוק!'),
(4, 'שוויון', 'הזכות ליחס שווה מהחוק וללא אפליה על רקע דת, גזע, מין או לאום.', 'כולם שווים מול החוק - גבר, אישה, כל דת ומוצא!'),
(4, 'זכות הצבעה', 'הזכות הפוליטית של אזרח בגיר להשתתף בבחירת נציגיו לשלטון באופן דמוקרטי.', 'כל אזרח מעל 18 יכול לבחור את נציגיו בכנסת!'),
(4, 'חופש ביטוי', 'זכותו של אדם להביע את דעותיו, אמונותיו ורגשותיו בכל דרך פומבית אפשרית.', 'אתה יכול לומר מה שאתה חושב - זו זכות חשובה!'),
(4, 'זכויות מיעוטים', 'זכויות קבוצתיות הניתנות למיעוטים דתיים ולאומיים כדי לשמר את תרבותם, שפתם וזהותם.', 'ערבים, דרוזים, צ''רקסים - לכל קבוצה זכויות שמורות!'),
(4, 'זכויות נשים', 'הזכות לשוויון הזדמנויות ולהגנה מפני אפליה במקומות עבודה, בחברה ובחוק.', 'נשים בישראל שוות לגברים בזכויות ובהזדמנויות!'),

-- יחידה 5: המערכת הפוליטית - בחירות ומפלגות
(5, 'מערכת הבחירות', 'הליך דמוקרטי יחסי, ארצי ורשימתי שבו בוחרים האזרחים את 120 חברי הכנסת.', 'כל 4 שנים בוחרים 120 חברי כנסת בפרופורציה!'),
(5, 'מפלגות', 'התארגנויות פוליטיות הפועלות להשגת עוצמה שלטונית כדי לממש את האידיאולוגיה שלהן.', 'קבוצות עם רעיונות דומים - ליכוד, עבודה, יש עתיד!'),
(5, 'קואליציה', 'ברית בין מפלגות המהוות יחד רוב (לפחות 61 ח"כים) ומרכיבות את הממשלה המכהנת.', 'מפלגות שמתאחדות לשלטון - יחד יש להן רוב בכנסת!'),
(5, 'אופוזיציה', 'המפלגות שאינן שותפות בקואליציה, שתפקידן לפקח על הממשלה ולהוות חלופה שלטונית.', 'מפלגות שלא בממשלה - בודקות ומבקרות את השלטון!'),
(5, 'ראש הממשלה', 'מנהיג הרשות המבצעת, נתמך על ידי הקואליציה ומוביל את מדיניות המדינה.', 'מנהיג הקואליציה - מנהל את המדינה ומקבל החלטות!'),
(5, 'נשיא המדינה', 'ראש המדינה שסמכויותיו טקסיות בעיקר (כמו הטלת הרכבת הממשלה או חנינה).', 'סמל המדינה - מקבל שגרירים וחותם על חוקים!'),

-- יחידה 6: כלכלת ישראל
(6, 'כלכלת שוק', 'מדיניות כלכלית המעודדת תחרות חופשית, יוזמה פרטית ומינימום התערבות מדינה.', 'עסקים פרטיים מתחרים - מחירים נקבעים לפי ביקוש והיצע!'),
(6, 'מעורבות הממשלה', 'התערבות המדינה במשק כדי למנוע כשלים, לספק ביטחון סוציאלי ולצמצם פערים.', 'הממשלה מסייעת - חינוך, בריאות, רווחה לכולם!'),
(6, 'תקציב המדינה', 'חוק ממשלתי הקובע את פירוט ההוצאות וההכנסות המתוכננות של המדינה לשנה קלנדרית.', 'הכנסות (מיסים) מול הוצאות - צריך איזון שנתי!'),

-- יחידה 7: ירושלים
(7, 'מעמד ירושלים', 'על פי חוק יסוד, ירושלים השלמה והמאוחדת היא בירת ישראל לנצח.', '1967: ירושלים המאוחדת - בירת ישראל לנצח!'),
(7, 'האוכלוסייה בירושלים', 'הרכב דמוגרפי מורכב בעיר הכולל אוכלוסייה יהודית וערבית במתח מתמיד.', 'כ-900 אלף תושבים - יהודים, מוסלמים, נוצרים!'),
(7, 'הר הבית והכותל', 'המקומות הקדושים ביותר ליהדות ולאסלאם, המהווים מוקד לחיכוך פוליטי ודתי.', 'מקום קדוש ליהודים, מוסלמים, נוצרים - יחד!'),
(7, 'הממשל בירושלים', 'ניהול העיר המאוחדת על ידי עירייה אחת תוך מתן מענה לצרכים של אוכלוסיות שונות.', 'עירייה מנהלת שירותים - חינוך, תברואה, תחבורה!'),
(7, 'הבעיות בירושלים', 'אתגרים ביטחוניים, כלכליים (עוני), לאומיים ודמוגרפיים המאפיינים את הבירה.', 'פערים כלכליים, מחסור בדיור, משברים ביטחוניים!'),
(7, 'הר הצופים', 'מובלעת היסטורית במזרח העיר המהווה מרכז אקדמי ורפואי (האוניברסיטה העברית והדסה).', 'האוניברסיטה העברית - מרכז מחקר עולמי בירושלים!'),
(7, 'מוזיאונים ותרבות', 'מוסדות לאומיים המשמרים ומציגים את המורשת והתרבות היהודית והישראלית.', 'מוזיאון ישראל, יד ושם - תרבות עשירה בבירה!'),
(7, 'תיירות בירושלים', 'ענף כלכלי משמעותי הנשען על עולי רגל ותיירים המבקרים באתרים הקדושים.', '3 מיליון תיירים בשנה - באים לראות את העתיקה!'),
(7, 'האתגרים העתידיים', 'הצורך לפתח את העיר תוך שמירה על דו-קיום ועל מעמדה הלאומי והבינלאומי.', 'שלום, שוויון, פיתוח - ירושלים של כולנו!'),

-- יחידה 8: הסכסוך הישראלי-פלסטיני
(8, 'הרקע להסכסוך', 'התנגשות בין שתי תנועות לאומיות - ציונית ופלסטינית - על הזכות לריבונות באותו חבל ארץ.', 'שני עמים, ארץ אחת - שניהם רוצים אותה לעצמם!'),
(8, 'הסכסוך עצמו', 'העימות הפוליטי, הצבאי והאזרחי המתמשך בין ישראלים לפלסטינים.', 'יהודים וערבים נלחמים על הארץ - מאז 1920!'),
(8, 'הפתרונות המוצעים', 'מודלים שונים להסדר מדיני: שתי מדינות לשני עמים, מדינה אחת, או הסדרים אזוריים.', 'שתי מדינות, מדינה אחת, קונפדרציה - רעיונות שונים!'),
(8, 'תהליך השלום', 'סדרת המגעים והמשאים ומתנים שנועדו להביא להסדר קבע ביחסי ישראל-פלסטינים.', '1993: אוסלו - הסכם בין ישראל לפלסטינים!'),
(8, 'הסכמי אוסלו', 'הסכמי ביניים (1993) במסגרתם הוכרה אש"ף כנציג הפלסטינים והוקמה הרשות הפלסטינית.', '1993: הכרה הדדית, אוטונומיה, פתח ורצועה!'),
(8, 'ההתנתקות (2005)', 'נסיגה ישראלית חד-צדדית מרצועת עזה ופינוי מלא של היישובים הישראלים משם.', '2005: ישראל פינתה 21 יישובים מרצועת עזה!'),
(8, 'גדר ההפרדה', 'מכשול פיזי שהוקם ביו"ש כדי למנוע חדירת מחבלים, שעורר מחלוקת משפטית ובינלאומית.', '2002: גדר ביטחון נגד פיגועים - מאוד שנויה במחלוקת!'),
(8, 'האינתיפאדות', 'גלי התקוממות אלימים (1987, 2000) של האוכלוסייה הפלסטינית נגד השלטון הישראלי.', '1987, 2000: התקוממות פלסטינית אלימה נגד ישראל!'),
(8, 'המחסומים', 'נקודות בידוק ביטחוניות ביו"ש שנועדו למנוע טרור אך פוגעות בחופש התנועה הפלסטיני.', 'בדיקות ביטחון - מקשות על פלסטינים ומקשות עלינו!'),
(8, 'המאבק הבינלאומי', 'ניסיונות של גורמים זרים, ביניהם האו"ם והמעצמות, לתווך או להפעיל לחץ בסכסוך.', 'האו"ם, ארה"ב, אירופה - כולם מעורבים בסכסוך!'),
(8, 'חמאס', 'תנועה איסלאמית קיצונית שהשתלטה על עזה ב-2007 וקוראת להשמדת ישראל.', 'ארגון טרור איסלאמי - שולט ברצועת עזה מאז 2007!'),
(8, 'הרשות הפלסטינית', 'מועצה מנהלתית פלסטינית שהוקמה בהסכמי אוסלו ושולטת בחלקים מיהודה ושומרון.', 'ממשל פלסטיני - שלטון עצמי ביהודה ושומרון!'),
(8, 'התנחלויות', 'יישובים שקמו ביהודה ושומרון לאחר מלחמת ששת הימים, ושאלת עתידם שנויה במחלוקת חריפה.', 'יישובים יהודיים ביהודה ושומרון - מאוד שנויים במחלוקת!'),
(8, 'האתגרים הנוכחיים', 'מציאות של היעדר אופק מדיני, אלימות תקופתית וטרור מתמשך שמקשים על פיוס.', 'אלימות, פיגועים, חוסר אמון - קשה להגיע לשלום!'),
(8, 'האתגרים העתידיים', 'מציאת מתווה להסדר שיבטיח את ביטחון ישראל ואת מימוש השאיפות הלאומיות הפלסטיניות.', 'שלום, ביטחון, שגשוג - תקווה לדורות הבאים!'),
(8, 'פיגועים', 'פעולות טרור מכוונות נגד אזרחים שנועדו לזרוע פחד ולהשיג הישגים פוליטיים.', 'טרור נגד אזרחים - מטרה להרוס את תהליך השלום!'),

-- יחידה 9: מדינת ישראל והעולם היהודי
(9, 'תפוצות ישראל', 'הקהילות היהודיות ברחבי העולם (מחוץ לישראל), המהוות כמחצית מהעם היהודי.', 'יהודים בכל העולם - 15 מיליון, רק 7 מיליון בישראל!'),
(9, 'קשר ליהדות העולם', 'התפיסה שישראל היא מדינתו של העם היהודי כולו ושיש לה מחויבות ליהודי התפוצות.', 'ישראל מרכז ליהודים בכל העולם - בית וזהות!'),
(9, 'העלייה', 'הגירת יהודים לישראל (חוק השבות), המהווה את אחד מעמודי התווך של התנועה הציונית.', 'יהודים עולים מכל העולם - חוק השבות מאפשר!'),
(9, 'התיקון לעלייה', 'מדיניות עדכנית בנוגע לחוק השבות (לדוגמה: סעיף הנכד) המעוררת מחלוקת ציבורית בישראל.', '2007: בדיקות קשות יותר - אבל עדיין מקבלים יהודים!'),
(9, 'יחסי דתות', 'הדו-קיום ומערכות היחסים המורכבות בין הקבוצות הדתיות השונות (יהודים, מוסלמים, נוצרים).', 'יהודים, מוסלמים, נוצרים - כולם חיים יחד בארץ!'),
(9, 'היהדות בישראל', 'הביטוי הציבורי והממסדי של הדת היהודית במדינה (שבת, כשרות, נישואין).', 'רבנות ראשית, כשרות, בתי כנסת - יהדות חיה!'),
(9, 'זכויות דתיות', 'חופש הדת והפולחן הניתן לכל עדה דתית לנהל את מוסדותיה באופן עצמאי.', 'חופש דת לכל - יהודים, מוסלמים, נוצרים, דרוזים!'),
(9, 'המחלוקות הדתיות', 'המתח והשסע החברתי בין חילונים ודתיים סביב אופייה של השבת והמרחב הציבורי.', 'דת ומדינה - איך משלבים? מחלוקת גדולה בחברה!'),
(9, 'היהדות והדמוקרטיה', 'אתגר מתמיד לאזן בין ערכיה היהודיים של המדינה לבין עקרונות הדמוקרטיה וזכויות האדם.', 'איך משלבים יהדות ודמוקרטיה? אתגר מתמיד!'),
(9, 'תיקון עולם', 'השאיפה לפעול למען חברה צודקת ומוסרית כחלק מהחזון היהודי והכלל-אנושי של המדינה.', 'ישראל מנסה לתקן את העולם - מדינה צודקת ומוסרית!'),

-- יחידה 10: מדינת ישראל בעולם
(10, 'יחסי החוץ', 'הפעילות הדיפלומטית שנועדה לבסס את מעמדה הבינלאומי של ישראל, כלכלתה וביטחונה.', '163 מדינות מכירות בישראל - יחסים דיפלומטיים!'),
(10, 'האו"ם', 'ארגון בינלאומי המהווה זירה שבה ישראל נאלצת לעיתים קרובות להתמודד עם החלטות עוינות.', '1949: ישראל התקבלה לאו"ם - מדינה מוכרת בעולם!'),
(10, 'ארה"ב', 'בת הברית האסטרטגית המרכזית של ישראל, המספקת לה תמיכה כלכלית, צבאית ומדינית במועצת הביטחון.', 'הבעליית של ארה"ב - בעלת הברית החשובה ביותר!'),
(10, 'אירופה', 'שותף הסחר הגדול ביותר של ישראל המבקר לעיתים את המדיניות הישראלית בנושא הפלסטיני.', 'האיחוד האירופי - שותף מסחרי ופוליטי חשוב!'),
(10, 'מדינות ערב', 'מערכת יחסים אזורית הנעה בין הסכמי שלום (ירדן, מצרים, הסכמי אברהם) לבין יריבות מתמשכת.', 'מצרים, ירדן - שלום; אחרות - עדיין אויבים!'),
(10, 'שגרירויות', 'הנציגויות הישראליות הפזורות בעולם המקדמות שיתופי פעולה ותורמות למערך ההסברה.', 'ישראל מחזיקה שגרירויות ב-80 מדינות - נוכחות עולמית!'),

-- יחידה 11: ביטחון ישראל
(11, 'איומים על ישראל', 'מגוון איומים הכוללים טרור, ארגונים חמושים (פרוקסי) והתגרענות איראנית.', 'טרור, טילים, איראן - איומים ביטחוניים מתמידים!'),
(11, 'צה"ל', 'צבא ההגנה לישראל הפועל כצבא העם ומושתת על שירות חובה והגנה מפני אויבי המדינה.', 'צבא ההגנה לישראל - 170 אלף חיילים מגנים עלינו!'),
(11, 'מלחמות ישראל', 'מערכות צבאיות שישראל נאלצה לנהל לאורך השנים כדי להבטיח את קיומה וריבונותה.', '1948, 1967, 1973, 1982, 2006 - מלחמות על קיום!'),
(11, 'מלחמת ששת הימים (1967)', 'מלחמה שבה ישראל הביסה תוך ימים ספורים צבאות ערביים וסיפחה שטחים נרחבים.', '1967: ניצחון גדול - כבשנו גולן, יהודה, שומרון, סיני!'),
(11, 'מלחמת יום הכיפורים (1973)', 'מלחמה שפרצה בהפתעה וגרמה לאבדות כבדות ששינו את תפיסת הביטחון הלאומית.', '1973: הפתעה קשה, אבל ניצחון - מחיר כבד בנפגעים!'),
(11, 'מלחמת לבנון (1982)', 'מערכה שנועדה להרחיק את איום הטרור מהצפון אך הובילה לשהייה ממושכת בלבנון.', '1982: כבשנו לבנון להרחקת אויב - מלחמה ארוכה!'),
(11, 'מלחמת לבנון השנייה (2006)', 'עימות צבאי מול ארגון חיזבאללה שהתאפיין בירי טילים מאסיבי על העורף הישראלי.', '2006: מלחמה נגד חיזבאללה בלבנון - איומים מהצפון!'),
(11, 'מודיעין', 'מערכות הסיכול והאיסוף החשאי (מוסד, שב"כ, אמ"ן) המספקות התרעה טרם פגיעה בביטחון המדינה.', 'מוסד, שב"כ, אמ"ן - אוספים מידע על אויבים!'),
(11, 'גדר ההפרדה', 'מכשול הגנתי פיזי למניעת חדירת מחבלים, בעל השלכות משפטיות והומניטריות בינלאומיות.', '2002: גדר ביטחון - מפחיתה פיגועים אבל שנויה במחלוקת!'),
(11, 'האתגרים הביטחוניים', 'היערכות תמידית ללחימה במספר זירות (רב-זירתית) ולהגנה מול איומי טילים וטרור.', 'איראן, חיזבאללה, חמאס - איומים קיומיים מתמידים!'),
(11, 'פיתוח טכנולוגי', 'השקעה במערכות הגנה מתקדמות (כגון כיפת ברזל) לשימור היתרון האיכותי של ישראל באזור.', 'חדר, פלניאד, רפאל - ישראל מפתחת נשק מתקדם!'),
(11, 'העורף', 'החזית האזרחית בישראל, הנדרשת למוכנות מתמדת מול ירי טילים ואיומי חירום חברתיים.', 'אזרחים בבתים - צריכים הגנה מטילים ופיגועים!'),
(11, 'חיל האוויר', 'הזרוע האווירית המהווה מרכיב הרתעתי אסטרטגי ויכולת תקיפה מרכזית של צה"ל.', 'כוח אווירי חזק - 600 מטוסים, מוכן לכל משימה!'),
(11, 'חיל הים', 'הזרוע הימית המאבטחת את המים הכלכליים, נתיבי הסחר ואת חופי מדינת ישראל.', 'כוח ימי - מגן על החוף ומאפשר הסגר ימי!'),

-- יחידה 12: חברה ותרבות בישראל
(12, 'האוכלוסייה', 'כלל תושבי ישראל, המורכבים מפסיפס דמוגרפי רב-תרבותי (יהודים, ערבים, דרוזים, ועוד).', '9.5 מיליון איש - יהודים, ערבים, אחרים - מגוון גדול!'),
(12, 'דמוגרפיה', 'הרכב האוכלוסייה, המאופיין בצמיחה מהירה ובשינויים בשיעור קבוצות המיעוט (כגון חרדים וערבים).', '72% יהודים, 21% ערבים - אוכלוסייה גדלה ומשתנה!'),
(12, 'עלייה', 'הגעת עולים מתמשכת המעצבת את הכלכלה, התרבות והזהות של החברה הישראלית.', '3 מיליון עולים מאז 1948 - מכול העולם לישראל!'),
(12, 'חינוך', 'מערכת ממלכתית המפוצלת לזרמים שונים ונועדה להנחיל ערכים משותפים וכישורי חיים.', 'חינוך חובה 12 שנים - לומדים אזרחות, היסטוריה, עברית!'),
(12, 'תרבות', 'יצירה מקומית ועשירה המשלבת השפעות יהודיות, מערביות ומזרח-תיכוניות באמנות ובשפה.', 'ספרות, מוזיקה, תיאטרון - תרבות ישראלית עשירה!'),
(12, 'ספורט', 'פעילות תחרותית ועממית בישראל המשמשת לעיתים קרובות כגורם חברתי מאחד במדינה המקוטבת.', 'כדורגל, כדורסל, אולימפיאדה - ספורט מחבר את האומה!'),
(12, 'דת', 'חופש הפולחן והדת הקיים בישראל, המאפשר חיים בצוותא של קהילות שונות, תוך מתח חברתי מתמיד.', 'יהודים, מוסלמים, נוצרים, דרוזים - חופש דת לכל!'),
(12, 'החברה הישראלית', 'חברה פלורליסטית אך משוסעת, הנדרשת להתמודד עם הבדלים עמוקים באידיאולוגיות ובאורחות החיים.', 'חברה פלורליסטית - כולם חיים יחד באותה ארץ!'),

-- יחידה 13: התשתיות בישראל
(13, 'תחבורה', 'מערכות כבישים, מסילות ותחבורה ציבורית הנדרשות לפיתוח מואץ עקב צפיפות האוכלוסין.', 'כבישים, רכבות, אוטובוסים, רכבת קלה - מתחברים!'),
(13, 'תקשורת', 'תשתיות טכנולוגיה ואינטרנט מתקדמות המציבות את ישראל כמעצמת חדשנות גלובלית ("אומת הסטארט-אפ").', 'טלפון, אינטרנט, סלולרי - כולם מחוברים לעולם!'),
(13, 'אנרגיה', 'משק האנרגיה הישראלי, הכולל גילויי גז טבעי משמעותיים המבטיחים עצמאות אנרגטית למדינה.', 'חשמל, גז, דלק - אנרגיה לכל הבתים והמפעלים!'),
(13, 'מים', 'התמודדות עם מצוקת משק המים האזורי באמצעות מפעלי התפלה לאומיים וטכנולוגיות מיחזור מתקדמות.', 'מתפלה, מים טהורים - מים לכל הארץ!'),

-- יחידה 14: הסביבה בישראל
(14, 'בעיות סביבתיות', 'התמודדות עם פליטות, צפיפות, זיהום אוויר ופגיעה בשטחים פתוחים הנגזרים מפיתוח כלכלי מואץ.', 'זיהום אוויר, מים, קרקע - הארץ זקוקה לטיפול!'),
(14, 'שימור טבע', 'המאמץ הלאומי לשמור על החי, הצומח והנוף הייחודי לארץ ישראל באמצעות שמורות ופארקים.', 'שמורות טבע, פארקים - שומרים על הצמחים והחיות!'),
(14, 'חקיקה סביבתית', 'החוקים והתקנות הממשלתיות שנועדו לקדם פיתוח בר-קיימא ולהעניש גורמים מזהמים.', 'חוקים להגנת הסביבה - מפחיתים זיהום ומקדמים שימור!'),

-- יחידה 15: מדיניות החוץ של ישראל
(15, 'עקרונות מדיניות החוץ', 'החתירה לשמירה על הקיום והביטחון הלאומי, לצד ניסיונות להשתלבות וללגיטימציה דיפלומטית בעולם.', 'ביטחון, שלום, שיתוף פעולה - מטרות מרכזיות!'),
(15, 'אסטרטגיה ביטחונית', 'תפיסת בניין הכוח הישראלית המושתתת על הרתעה חזקה, הכרעה מהירה ויצירת בריתות אזוריות.', 'הגנה עצמית, התעצמות, בריתות - להישאר חזקים!'),
(15, 'מדיניות שלום', 'המאמצים המדיניים להשגת הסכמי שלום עם מדינות ערב כדרך לקיבוע יציבות ביטחונית במזרח התיכון.', 'הסדרים, משא ומתן, הסכמים - מחפשים שלום!'),
(15, 'יחסי ארה"ב', 'הברית הדיפלומטית והצבאית העמוקה עם המעצמה המהווה את משענתה המדינית המרכזית של ישראל בעולם.', 'בעליית ארה"ב - שותף אסטרטגי החשוב ביותר!'),
(15, 'יחסי אירופה', 'שותפות סחר מהותית, הנלווית לעיתים קרובות ללחצים מדיניים מצידה בנוגע לסכסוך הפלסטיני.', 'איחוד אירופי - שותף כלכלי ופוליטי חשוב!'),

-- יחידה 16: אתגרים עתידיים
(16, 'אתגרים ביטחוניים', 'הצורך לבלום את התעצמות ארגוני הטרור ואת תכנית הגרעין האיראנית המאיימת על קיום המדינה.', 'איראן, חיזבאללה, חמאס - איומים שמתפתחים כל הזמן!'),
(16, 'אתגרים כלכליים', 'הצורך בהורדת יוקר המחיה, בצמצום פערי העושר, ובקידום תעסוקה לאוכלוסיות הפריפריה והמיעוטים.', 'פערים, יוקר מחייה, תעסוקה - צריך פתרונות!'),
(16, 'אתגרים חברתיים', 'שמירה על לכידות לאומית בחברה משוסעת, והתמודדות מתמשכת עם זהותה של ישראל כמדינה יהודית ודמוקרטית.', 'פלורליזם, דת ומדינה, זהות - איך לשמור אחדות?');